import { Permissao, parsePermissao } from './Permissao';

export type DadosUsuario = {
  id: string;
  nome: string;
  email: string;
  senha?: string;
  permissao: Permissao;
  created_at?: string;
  updated_at?: string;
};

export type EntradaFormularioUsuario = {
  nome: string;
  email: string;
  senha?: string;
  permissao: Permissao | string;
  matricula?: number | null;
  curso?: string;
  formacao?: string;
  codigo?: number | null;
  telefone?: string;
  dataNascimento?: string;
};

/** Linha retornada pelo Supabase (`profiles`). */
export type PerfilDb = {
  id: string;
  name?: string;
  nome?: string;
  email: string;
  role?: string;
  permissao?: string;
  matricula?: number | null;
  curso?: string;
  formacao?: string;
  codigo?: number | null;
  telefone?: string;
  data_nascimento?: string;
  created_at?: string;
  updated_at?: string;
};

export function perfilDbParaDados(row: PerfilDb): DadosUsuario {
  return {
    id: row.id,
    nome: (row.nome || row.name || '').trim() || row.email.split('@')[0],
    email: row.email,
    permissao: parsePermissao(row.permissao || row.role),
    created_at: row.created_at,
    updated_at: row.updated_at,
  };
}

export class Usuario {
  id: string;
  nome: string;
  email: string;
  senha?: string;
  permissao: Permissao;
  created_at?: string;
  updated_at?: string;

  constructor(dados: DadosUsuario) {
    this.id = dados.id;
    this.nome = dados.nome;
    this.email = dados.email;
    this.senha = dados.senha;
    this.permissao = dados.permissao;
    this.created_at = dados.created_at;
    this.updated_at = dados.updated_at;
  }

  podeGerenciarUsuarios(): boolean {
    return false;
  }

  podeGerenciarMetodosEstudo(): boolean {
    return false;
  }

  podeGerenciarMaterias(): boolean {
    return false;
  }

  podeVisualizarMaterias(): boolean {
    return false;
  }
}
